#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int val[] = {1000, 900, 500, 400, 100, 90, 50, 40, 10, 9, 5, 4, 1};
    char *syb[] = {"M", "CM", "D", "CD", "C", "XC", "L", "XL", "X", "IX", "V", "IV", "I"};
    for (int i = 0; i < 13; i++) {
        while (n >= val[i]) {
            printf("%s", syb[i]);
            n -= val[i];
        }
    }
    return 0;
}

